require('dotenv').config();
const express = require('express');
const cors = require('cors');
const { wrapDocuments } = require('@govtechsg/open-attestation');
const fs = require('fs');
const multer = require('multer');
const { ethers } = require('ethers');

const app = express();
app.use(cors());
app.use(express.json());

// Vercel only allows writing to /tmp
const upload = multer({ dest: '/tmp/uploads/' });

// Health check for Vercel
app.get('/api/health', (req, res) => {
  res.json({ status: 'ok', message: 'Backend is running' });
});

// Create (Wrap) Certificate
app.post('/api/cert/create', (req, res) => {
  try {
    const { id, recipientName, courseName, issuedOn } = req.body;

    const rawDocument = {
      "id": id || `CERT-${Date.now()}`,
      "issuedOn": issuedOn || new Date().toISOString(),
      "name": "Edusave Award for Achievement, Good Leadership and Service (EAGLES) 2017",
      "description": "Students who are within the top 10% of their school’s level and course in terms of academic performance, and have demonstrated good conduct.",
      "$template": {
        "name": "custom",
        "type": "EMBEDDED_RENDERER",
        "url": process.env.RENDERER_URL || "https://demo-renderer.opencerts.io"
      },
      "issuers": [
        {
          "name": "Ministry of Education",
          "did": "DID:SG-UEN:U18274928E",
          "uen": "U18274928E",
          "url": "https://www.moe.gov.sg",
          "email": "registrar@moe.gov.sg",
          "documentStore": process.env.DOCUMENT_STORE_ADDRESS || "0xb87d777614cC710Ed9a69ae6AcdFECc9b81AaBde",
          "identityProof": {
            "type": "DNS-TXT",
            "location": process.env.DNS_NAME || "demo.champslms.com"
          }
        }
      ],
      "data": {
        "html": "<h1 style='color:green'>hiii</h1><p>only html show</p>"
      },
      "recipient": {
        "name": recipientName || "velraj2",
        "email": "velraj@test.com",
        "id": "1"
      },
      "award": {
        "instituteName": "MindChamps",
        "achievementArea": courseName || "Parent San",
        "achievementDate": issuedOn || "2026-04-17",
        "address": "123 Champs Avenue, Singapore",
        "contact": "+65 1234 5678"
      },
      "signature": {
        "name": "Jack Lim",
        "designation": "Executive Director",
        "signature": "data:image/png;base64,"
      }
    };

    // wrapDocument is used for a single document, but wrapDocuments takes an array
    const wrappedDocuments = wrapDocuments([rawDocument]);
    
    // Return the single wrapped document
    res.json({
      success: true,
      message: 'Certificate created and wrapped successfully.',
      certificate: wrappedDocuments[0]
    });

  } catch (error) {
    console.error("Error creating certificate:", error);
    res.status(500).json({ 
      success: false, 
      error: error.message,
      hint: "Check if all environment variables (RPC_URL, PRIVATE_KEY, etc.) are set in Vercel."
    });
  }
});

app.post('/api/cert/issue', async (req, res) => {
  const { merkleRoot } = req.body;
  if (!merkleRoot) {
    return res.status(400).json({ success: false, error: "merkleRoot is required" });
  }
  
  try {
    const rpcUrl = process.env.RPC_URL;
    const privateKey = process.env.PRIVATE_KEY;
    const contractAddress = process.env.DOCUMENT_STORE_ADDRESS;

    // Fallback to mock if completely unconfigured or just missing parts
    if (!rpcUrl || !privateKey || !contractAddress) {
      console.warn("⚠️  Missing .env configurations. Skipping actual blockchain transaction and simulating success for local dev.");
      return res.json({
          success: true,
          message: 'Mock issuance successful! The root has been logged.',
          txHash: '0xmocktransactionhash123456789'
      });
    }

    // 1. Connect to Ethereum
    const provider = new ethers.providers.JsonRpcProvider(rpcUrl);
    const wallet = new ethers.Wallet(privateKey, provider);
    
    // 2. Connect to Smart Contract
    const abi = ["function issue(bytes32 node) public"];
    const contract = new ethers.Contract(contractAddress, abi, wallet);

    // 3. PAY GAS HERE: Send the transaction
    const tx = await contract.issue(`0x${merkleRoot}`);
    await tx.wait(); // Wait for blockchain confirmation

    console.log("Certificate successfully issued to blockchain! Tx Hash:", tx.hash);
    res.json({ success: true, txHash: tx.hash });
  } catch (error) {
    console.error("Error issuing certificate to blockchain:", error);
    // Provide more detail in the JSON response to help debugging
    res.status(500).json({ success: false, error: error.message, stack: error.stack });
  }
});

const PORT = process.env.PORT || 3000;

if (require.main === module) {
  app.listen(PORT, () => {
    console.log(`OpenCerts Backend running on http://localhost:${PORT}`);
  });
}

module.exports = app;
